import React, { memo } from "react";

function CardResumen({ titulo, valor, subtitulo, icono, colorClase = "text-primary-600", bgClase = "bg-primary-50" }) {
  return (
    <div className={`rounded-xl border border-gray-200 bg-white p-5 shadow-sm hover:shadow-md transition-shadow duration-200 animate-fade-in`}>
      <div className="flex items-start justify-between">
        <div>
          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide">{titulo}</p>
          <p className={`text-4xl font-bold mt-1 ${colorClase}`}>{valor}</p>
          {subtitulo && (
            <p className="text-sm text-gray-500 mt-1">{subtitulo}</p>
          )}
        </div>
        <div className={`w-12 h-12 rounded-xl ${bgClase} flex items-center justify-center text-2xl`}>
          {icono}
        </div>
      </div>
    </div>
  );
}

export default memo(CardResumen);
